import React, { useState, useEffect } from 'react';
import { 
  Users, CreditCard, Settings, Bell, Home, User, Lock, Mail, LogOut, 
  Smartphone, Zap, ShieldCheck, CheckCircle2, ArrowLeft, ChevronRight, 
  Globe, CreditCard as CardIcon, Eye, Download, X, Upload, Trash2, Save,
  ShieldAlert, Landmark, Building, Menu, FileText, Calendar, Clock, 
  HandCoins, Check, Ban, Filter
} from 'lucide-react';

// --- MAIN APPLICATION COMPONENT ---
const App = () => {
  const [userRole, setUserRole] = useState(null); // 'admin' or 'tenant'
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [selectedTenant, setSelectedTenant] = useState(null);

  // --- SRS DATA ENGINE ---
  const [tenants, setTenants] = useState([
    { 
      id: 1, 
      name: 'Rajesh Kumar', 
      room: 'A-101', 
      status: 'Pending Approval', 
      amount: 12500, 
      dueDate: '2024-04-05', 
      phone: '+91 98765 43210', 
      email: 'rajesh.k@example.com', 
      joinDate: '12 Jan 2024',
      prevReading: 1020,
      currReading: 1150,
      unitPrice: 8,
      lateFeePerDay: 50,
      history: [
        { date: '2024-03-01', month: 'March', amount: 13200 },
        { date: '2024-02-01', month: 'February', amount: 12900 }
      ]
    },
    { 
      id: 2, 
      name: 'Anita Sharma', 
      room: 'B-204', 
      status: 'Paid', 
      amount: 15000, 
      dueDate: '2024-04-10', 
      phone: '+91 88776 65544', 
      email: 'anita.s@example.com', 
      joinDate: '20 Feb 2024',
      prevReading: 450,
      currReading: 510,
      unitPrice: 8,
      lateFeePerDay: 50,
      history: []
    }
  ]);

  const logout = () => {
    setUserRole(null);
    setActiveTab('Dashboard');
  };

  if (!userRole) {
    return (
      <div className="h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="max-w-md w-full space-y-8 text-center">
          <div className="inline-flex items-center gap-3 font-black italic text-3xl text-white mb-8">
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center not-italic">H</div> Homely
          </div>
          <div className="grid grid-cols-1 gap-4">
            <button onClick={() => setUserRole('admin')} className="p-8 bg-white rounded-[2.5rem] hover:bg-indigo-50 transition-all group text-left">
              <Building className="text-indigo-600 mb-4" size={32}/>
              <h3 className="font-black italic text-xl">Landlord Portal</h3>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Manage Property & Payments</p>
            </button>
            <button onClick={() => setUserRole('tenant')} className="p-8 bg-slate-800 rounded-[2.5rem] hover:bg-slate-700 transition-all group text-left border border-slate-700">
              <User className="text-indigo-400 mb-4" size={32}/>
              <h3 className="font-black italic text-xl text-white">Tenant Portal</h3>
              <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-1">View Bills & Pay Rent</p>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return userRole === 'admin' ? (
    <AdminPortal tenants={tenants} setTenants={setTenants} activeTab={activeTab} setActiveTab={setActiveTab} logout={logout} />
  ) : (
    <TenantPortal tenant={tenants[0]} activeTab={activeTab} setActiveTab={setActiveTab} logout={logout} />
  );
};

// --- LANDLORD / ADMIN PORTAL ---
const AdminPortal = ({ tenants, setTenants, activeTab, setActiveTab, logout }) => {
  const [profileOpen, setProfileOpen] = useState(false);

  // SRS Logic: Calculations
  const calculateElec = (t) => (t.currReading - t.prevReading) * t.unitPrice;
  const calculateLate = (t) => {
    const due = new Date(t.dueDate);
    const today = new Date();
    const diff = Math.ceil((today - due) / (1000 * 60 * 60 * 24));
    return diff > 5 ? (diff - 5) * t.lateFeePerDay : 0;
  };
  const getTotal = (t) => t.amount + calculateElec(t) + calculateLate(t);

  const handleApproval = (id, status) => {
    setTenants(prev => prev.map(t => t.id === id ? { ...t, status: status === 'ok' ? 'Paid' : 'Rejected' } : t));
  };

  const pending = tenants.filter(t => t.status === 'Pending Approval');

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <aside className="w-72 bg-slate-900 text-white p-8 hidden md:flex flex-col">
        <div className="flex items-center gap-3 font-black italic text-xl mb-12">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center not-italic">H</div> Homely
        </div>
        <nav className="space-y-2">
          {['Dashboard', 'Tenants', 'Meter Updates', 'Settings'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 shadow-lg shadow-indigo-900' : 'text-slate-500 hover:text-white'}`}>
              {tab === 'Dashboard' && <Home size={18}/>}
              {tab === 'Tenants' && <Users size={18}/>}
              {tab === 'Meter Updates' && <Zap size={18}/>}
              {tab === 'Settings' && <Settings size={18}/>}
              {tab}
            </button>
          ))}
        </nav>
      </aside>

      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="h-24 bg-white border-b px-12 flex items-center justify-between">
          <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{activeTab}</h2>
          <button onClick={logout} className="flex items-center gap-2 text-red-500 font-black text-[10px] uppercase tracking-widest"><LogOut size={16}/> Sign Out</button>
        </header>

        <main className="flex-1 overflow-y-auto p-12">
          {activeTab === 'Dashboard' && (
            <div className="space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <div className="bg-white p-10 rounded-[3rem] border shadow-sm">
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Pending Approvals</p>
                  <h3 className="text-4xl font-black italic text-amber-500">{pending.length}</h3>
                </div>
                <div className="bg-white p-10 rounded-[3rem] border shadow-sm">
                  <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Total Revenue</p>
                  <h3 className="text-4xl font-black italic text-emerald-600">₹{tenants.reduce((a, t) => a + (t.status === 'Paid' ? getTotal(t) : 0), 0).toLocaleString()}</h3>
                </div>
                <div className="bg-indigo-600 p-10 rounded-[3rem] text-white">
                  <p className="text-[10px] font-black uppercase mb-2">System Status</p>
                  <h3 className="text-4xl font-black italic">Active</h3>
                </div>
              </div>

              {/* Approval Queue */}
              <div className="bg-white rounded-[3.5rem] border overflow-hidden">
                <div className="p-10 border-b"><h3 className="text-xs font-black uppercase italic">Payment Approval Queue</h3></div>
                <table className="w-full text-left">
                  <thead className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase">
                    <tr><th className="px-10 py-6">Tenant</th><th className="px-10 py-6">Due Amount</th><th className="px-10 py-6 text-right">Action</th></tr>
                  </thead>
                  <tbody>
                    {pending.map(t => (
                      <tr key={t.id} className="border-b">
                        <td className="px-10 py-6 font-bold text-xs">{t.name} <span className="block text-[10px] font-normal text-slate-400">{t.room}</span></td>
                        <td className="px-10 py-6 font-black italic">₹{getTotal(t).toLocaleString()}</td>
                        <td className="px-10 py-6 text-right">
                          <div className="flex gap-2 justify-end">
                            <button onClick={() => handleApproval(t.id, 'ok')} className="p-2 bg-emerald-100 text-emerald-600 rounded-lg"><Check size={16}/></button>
                            <button onClick={() => handleApproval(t.id, 'reject')} className="p-2 bg-red-100 text-red-600 rounded-lg"><Ban size={16}/></button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {activeTab === 'Meter Updates' && (
            <div className="space-y-6">
               <h3 className="text-3xl font-black italic uppercase">Landlord Meter Input</h3>
               {tenants.map(t => (
                 <div key={t.id} className="bg-white p-8 rounded-[2.5rem] border flex items-center justify-between">
                   <div className="flex gap-6">
                     <div className="w-12 h-12 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black">{t.room}</div>
                     <div><p className="font-black italic">{t.name}</p><p className="text-[9px] uppercase font-bold text-slate-400">Previous: {t.prevReading}</p></div>
                   </div>
                   <div className="flex items-center gap-4">
                     <input type="number" placeholder="Enter New Reading" className="bg-slate-50 border rounded-xl px-4 py-3 text-xs font-bold w-40" />
                     <button className="bg-indigo-600 text-white px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest">Update</button>
                   </div>
                 </div>
               ))}
            </div>
          )}

          {activeTab === 'Tenants' && (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {tenants.map(t => (
                  <div key={t.id} className="bg-white p-10 rounded-[3rem] border hover:border-indigo-600 transition-all">
                    <div className="w-14 h-14 bg-slate-50 rounded-xl mb-6 flex items-center justify-center text-slate-300 font-black text-xl">{t.name[0]}</div>
                    <h4 className="text-xl font-black italic">{t.name}</h4>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-6">{t.room}</p>
                    <button className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest">View History</button>
                  </div>
                ))}
             </div>
          )}

          {activeTab === 'Settings' && (
            <div className="max-w-2xl bg-white p-12 rounded-[3.5rem] border space-y-8">
              <h3 className="text-2xl font-black italic uppercase">Global Config (SRS 2.1.3)</h3>
              <div className="space-y-4">
                <div className="p-6 bg-slate-50 rounded-3xl"><label className="text-[9px] font-black uppercase text-slate-400">Late Fee / Day</label><input type="text" defaultValue="₹50" className="w-full bg-transparent border-none text-xl font-black italic" /></div>
                <div className="p-6 bg-slate-50 rounded-3xl"><label className="text-[9px] font-black uppercase text-slate-400">Elec. Price / Unit</label><input type="text" defaultValue="₹8" className="w-full bg-transparent border-none text-xl font-black italic" /></div>
              </div>
              <button className="w-full py-5 bg-indigo-600 text-white rounded-[2rem] font-black uppercase text-[10px] tracking-widest shadow-xl shadow-indigo-100">Apply Changes</button>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

// --- TENANT PORTAL ---
const TenantPortal = ({ tenant, activeTab, setActiveTab, logout }) => {
  // Logic
  const elecUnits = tenant.currReading - tenant.prevReading;
  const elecBill = elecUnits * tenant.unitPrice;
  const lateFee = 0; // Hardcoded for demo
  const total = tenant.amount + elecBill + lateFee;

  return (
    <div className="flex h-screen bg-[#F8FAFC]">
      <aside className="w-72 bg-slate-900 text-white p-8 hidden md:flex flex-col">
        <div className="flex items-center gap-3 font-black italic text-xl mb-12">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center not-italic">H</div> Homely
        </div>
        <nav className="space-y-2">
          {['Dashboard', 'History', 'Settings'].map(tab => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`w-full flex items-center gap-4 px-6 py-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 shadow-lg shadow-indigo-900' : 'text-slate-500 hover:text-white'}`}>
              {tab === 'Dashboard' && <Home size={18}/>}
              {tab === 'History' && <Clock size={18}/>}
              {tab === 'Settings' && <Settings size={18}/>}
              {tab}
            </button>
          ))}
        </nav>
      </aside>

      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="h-24 bg-white border-b px-12 flex items-center justify-between">
          <h2 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">Tenant Portal / {activeTab}</h2>
          <button onClick={logout} className="text-red-500 font-black text-[10px] uppercase"><LogOut size={16}/></button>
        </header>

        <main className="flex-1 overflow-y-auto p-12">
          {activeTab === 'Dashboard' && (
            <div className="max-w-4xl space-y-10">
              <div className="bg-indigo-600 p-12 rounded-[4rem] text-white shadow-2xl relative overflow-hidden">
                <div className="relative z-10">
                  <p className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-2">Total Payable Amount</p>
                  <h3 className="text-6xl font-black italic mb-8">₹{total.toLocaleString()}</h3>
                  <div className="flex gap-4">
                    <button className="px-10 py-4 bg-white text-indigo-600 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-50 transition-all">Request Payment OK</button>
                    <div className="px-6 py-4 bg-white/10 rounded-2xl border border-white/20 text-[10px] font-black uppercase tracking-widest">Status: {tenant.status}</div>
                  </div>
                </div>
                <Zap className="absolute -right-10 -bottom-10 text-white/5" size={300} />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-white p-10 rounded-[3rem] border">
                  <h4 className="text-[10px] font-black text-slate-400 uppercase mb-6 flex items-center gap-2"><Zap size={14} className="text-indigo-600"/> Electricity (SRS 2.2)</h4>
                  <div className="space-y-4">
                    <div className="flex justify-between text-sm font-bold"><span>Units ({elecUnits})</span><span>₹{elecBill}</span></div>
                    <div className="text-[9px] text-slate-400 uppercase font-bold tracking-widest">Meter: {tenant.prevReading} → {tenant.currReading}</div>
                  </div>
                </div>
                <div className="bg-white p-10 rounded-[3rem] border">
                  <h4 className="text-[10px] font-black text-slate-400 uppercase mb-6 flex items-center gap-2"><Clock size={14} className="text-red-500"/> Late Fee (SRS 2.1)</h4>
                  <p className="text-sm font-bold">₹{lateFee} <span className="text-[9px] text-slate-400 ml-2 uppercase tracking-widest">Within Grace Period</span></p>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'History' && (
            <div className="space-y-8">
               <h3 className="text-3xl font-black italic uppercase">My Payment History</h3>
               <div className="bg-white rounded-[3rem] border overflow-hidden">
                 <table className="w-full text-left">
                    <thead className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase border-b">
                      <tr><th className="px-10 py-6">Date</th><th className="px-10 py-6">Description</th><th className="px-10 py-6 text-right">Amount</th></tr>
                    </thead>
                    <tbody>
                      {tenant.history.map((h, i) => (
                        <tr key={i} className="border-b last:border-0">
                          <td className="px-10 py-6 text-xs font-bold text-slate-400">{h.date}</td>
                          <td className="px-10 py-6 font-black italic text-xs">{h.month} Rent Paid</td>
                          <td className="px-10 py-6 text-right font-black italic text-emerald-600">₹{h.amount.toLocaleString()}</td>
                        </tr>
                      ))}
                    </tbody>
                 </table>
               </div>
            </div>
          )}

          {activeTab === 'Settings' && (
             <div className="max-w-2xl space-y-8">
                <div className="bg-white p-12 rounded-[3.5rem] border">
                   <h3 className="text-xl font-black italic uppercase mb-8">Personal Settings</h3>
                   <div className="space-y-4">
                      <div className="p-6 bg-slate-50 rounded-2xl">
                         <p className="text-[9px] font-black text-slate-400 uppercase mb-2">Registered Email</p>
                         <p className="font-black italic text-slate-900">{tenant.email}</p>
                      </div>
                      <div className="p-6 bg-slate-50 rounded-2xl">
                         <p className="text-[9px] font-black text-slate-400 uppercase mb-2">Room Number</p>
                         <p className="font-black italic text-slate-900">{tenant.room}</p>
                      </div>
                   </div>
                   <button className="w-full mt-10 py-5 bg-slate-900 text-white rounded-[2rem] font-black uppercase text-[10px] tracking-widest shadow-xl">Update Details</button>
                </div>
             </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;
